/// </summary>
public class UpdateDocumentRowDtoValidator : AbstractValidator<Prym.DTOs.Documents.UpdateDocumentRowDto>
{
    public UpdateDocumentRowDtoValidator()
    {
        RuleFor(x => x.ProductCode)
            .MaximumLength(50)
            .WithMessage("Il campo ProductCode non può superare 50 caratteri.");

        RuleFor(x => x.Description)
            .NotEmpty()
            .WithMessage("Il campo Description è obbligatorio.")
